/* --------------------------------------------------------------------------------------------
 * 4. TOTAL BREEDING CHANCE — the master multiplier chain. Two dispatcher cases,
 * `p._customBlock_Breeding`, N.js:12478-12486 (verbatim, all sub-terms named; unexpanded generic
 * dispatchers noted inline):
 *
 *   TotalBreedChance(species e, index f) =
 *     (1 + 10*GemItemsPurchased[119]/100)
 *     * (1 + (AlchVials.NewPet + AlchBubbles.NewPetRift*Rift[0]) / 100)
 *     * (1 + StampBonusOfTypeX("NewPet")/100)                    // further dispatcher, not expanded
 *     * (1 + MealBonus("Npet")/100)                                // further dispatcher, not expanded
 *     * Math.pow(Math.max(1, PetUpgBONUS(9)), TOTALKITCHEN/100)
 *     * BaseBreedChance(e,f) * 1stMulti(e,f) * 2ndMulti(e,f)
 *     * 3rdMulti(e,f) * 4thMulti(e,f) * 5thMulti(e,f);
 *
 *   TOTALKITCHEN = sum over all 10 kitchens' Cooking[k][6]+Cooking[k][7]+Cooking[k][8]
 *                  (speed+fire+luck ladle levels), STOPPING at the first kitchen with state==0
 *                  (i.e. the first UNPURCHASED kitchen breaks the loop — kitchens must be bought
 *                  in order for this sum to include them).
 *
 *   BaseBreedChance(e,f) — N.js:12478-12479, branches on whether the account is in "discover new
 *   species" mode (GenINFO[49]) vs "already discovered, rolling for shiny/upgrade" mode:
 *     if GenINFO[49] (new-species mode):
 *       if e>1: (1+OptionsListAccount[126]/100) * Math.pow(.92, f+8*(e-1)) * baseRarity
 *       else:   (1+OptionsListAccount[126]/100) * baseRarity
 *     else (already discovered):
 *       if f+2 > Breeding[1][e]: 1/max(1, rarityDivisor)
 *       else: 1
 *     where baseRarity = 1E-6 + .002/Math.max(1, RANDOlist[54][ PetStats[e][f][5] ])
 *     (PetStats[e][f][5] = the species' orderID, indexing RANDOlist[54]'s rarity-divisor table —
 *     same table used by the shiny-bonus chain in gamedata.mjs).
 *
 *   1stMulti(e,f)  = 1 + ceil(100 * (Breeding[4+e][f]/10)^1.9) / 100     // Gene Splicing lv, per world/species
 *   2ndMulti(e,f)  = GenINFO[53][0] (Breedability_Mobs unlocked)
 *                      ? 1 + ln(max(1, (Breeding[e+13][f]+1)^0.725))
 *                      : 1
 *   3rdMulti(e,f)  = GenINFO[53][1] (Rarity_of_the_Egg unlocked)
 *                      ? 1 + (.25*Breeding[0][0]^1.4 + (Breeding[0][0]/3)^6)
 *                      : 1
 *   4thMulti(e,f)  = GenINFO[53][2] (Pastpresent_Brood unlocked) ? <complex, scales with current
 *                      world GenINFO[44] and ratio of discovered species> : 1   — NOT fully
 *                      resolved in this pass; flag UNVERIFIED if a recipe needs the exact shape.
 *   5thMulti(e,f)  = GenINFO[53][3] (Failsafe_Restitution_Cloud unlocked)
 *                      ? Math.max(1, (OptionsListAccount[86]+1)^0.3)
 *                      : 1
 *
 * GeneticCost(e,f) (DNA-splicer gene-point cost) — N.js:12483:
 *   (10 + (5+f+Breeding[e+4][f]) + Math.pow(Math.max(f-3,1),1.7))
 *   * Math.pow(Math.max(f+1-6,1), 1.12)
 *   * Math.pow(1.052 + .01*Math.floor(Breeding[e+4][f]/10), Breeding[e+4][f])
 *   * Math.max(.01, 1 - PetUpgBONUS(1)/100);
 *
 * TotalEggCapacity — N.js:12468 (`"TotalEggCapacity"==d`):
 *   3 + PetUpgBONUS(2) + GemItemsPurchased[119] + Tasks[2][3][2]
 *
 * TotalTimeForEgg (hours -> seconds per egg produced) — N.js:12484:
 *   7200 / (1 + (MainframeBonus(111) + MealBonus("TimeEgg") + AlchBubbles.EggInc
 *     + 10*AchieveStatus(220) + 15*RiftStuff("RiftSkillBonus,10",1) + Summoning("VotingBonusz",16,0)) / 100)
 * -------------------------------------------------------------------------------------------- */
export const TOTAL_BREED_CHANCE_NOTE = "see file header comment above; 4thMulti's exact shape UNVERIFIED";

